using System.Collections;
using UnityEngine;

// Ataques de controlo (imobilização, telegraph em linha) — Etapa 2.1.

/// <summary>Rede que prende: se o alvo estiver perto, imobiliza-o (PlayerMotor2D.SetMovementLocked) durante "trapDuration" segundos.</summary>
[System.Serializable]
public class Attack_Net : EnemyAttack
{
    [Header("Rede")]
    [Tooltip("Distância ao alvo considerada 'acertou'.")]
    public float hitRadius = 2f;

    [Tooltip("Duração da imobilização do player, em segundos.")]
    public float trapDuration = 1.5f;

    public Attack_Net()
    {
        attackName = "Rede";
        range = 4f;
        damage = 0;
        requiresLineOfSight = true;
        prepTime = 0.5f;
        recoveryTime = 0.6f;
        cooldown = 4f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        if (ctx.IsTargetWithin(ctx.transform.position, hitRadius))
        {
            if (damage > 0) ctx.DamagePlayer(damage);
            ctx.TrapPlayer(trapDuration);
        }

        yield break;
    }
}

/// <summary>Raio/laser telegráfico: após o aviso (prepTime), fica activo durante "activeDuration", causando dano periódico a quem estiver dentro de "laserWidth" da linha.</summary>
[System.Serializable]
public class Attack_LaserTelegraph : EnemyAttack
{
    [Header("Raio/Laser")]
    [Tooltip("Direcção do raio a partir do inimigo (ex: (0,-1) para baixo, (1,0) para a frente).")]
    public Vector2 direction = Vector2.down;

    public float laserLength = 8f;

    [Tooltip("Distância máxima do alvo à linha do laser para ser atingido.")]
    public float laserWidth = 0.4f;

    [Tooltip("Duração em que o laser fica activo e pode causar dano (após o telegraph/prep).")]
    public float activeDuration = 0.5f;

    [Tooltip("Intervalo entre verificações de dano enquanto o laser está activo.")]
    public float tickInterval = 0.25f;

    public Attack_LaserTelegraph()
    {
        attackName = "Laser";
        range = 8f;
        prepTime = 0.6f;
        recoveryTime = 0.4f;
        cooldown = 3f;
    }

    public override IEnumerator Execute(EnemyAttackController ctx)
    {
        Vector2 origin = ctx.transform.position;
        Vector2 dir = direction.sqrMagnitude > 0.0001f ? direction.normalized : Vector2.down;
        Vector2 end = origin + dir * laserLength;

        float elapsed = 0f;

        while (elapsed < activeDuration)
        {
            if (ctx.Target != null && EnemyAttackController.DistanceToSegment(origin, end, ctx.Target.position) <= laserWidth)
                ctx.DamagePlayer(damage, knockbackForce);

            yield return new WaitForSeconds(tickInterval);
            elapsed += tickInterval;
        }
    }
}
